public class NullObject {
    interface Logger { void log(String msg); }
    static class ConsoleLogger implements Logger {
        public void log(String msg) { System.out.println(msg); }
    }
    static class NullLogger implements Logger {
        public void log(String msg) { /* do nothing */ }
    }
    static Logger getLogger(boolean enabled) {
        if (enabled) return new ConsoleLogger();
        return null;   // bug: should return new NullLogger()
    }
    public static void main(String[] args) {
        Logger log = getLogger(false);
        log.log("hello");  // NPE
    }
}
